urlset:

  {{ SITEURL }}/
  weekly
  1.0


  {{ SITEURL }}/archive/
  weekly
  0.8

{%- for page in category_pages %}

  {{ SITEURL }}/{{ page.url }}
  monthly
  0.6

{%- endfor %}
{%- for article in articles | sort(attribute='date', reverse=True) %}

  {{ SITEURL }}/{{ article.url }}
  {%- if article.modified %}
  {{ article.modified.strftime('%Y-%m-%d') }}
  {%- else %}
  {{ article.date.strftime('%Y-%m-%d') }}
  {%- endif %}
  monthly
  0.8

{%- endfor %}
